# Skeptic packet solve S45-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'transactions', 'cache_authoritative', 'cache_ttl_s', 'blob_store', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (record["cache_authoritative"] or record["transactions"] == "cache")) else 'REDESIGN_PERSISTENCE'

valid = {'case_id': 'CASO-IQU-045-1A', 'blob_store': 'object', 'transactions': 'relational', 'cache_authoritative': False, 'cache_ttl_s': 300}
invalid = {'case_id': 'CASO-IQU-045-1A', 'blob_store': 'object', 'transactions': 'relational', 'cache_authoritative': True, 'cache_ttl_s': 300}
incomplete = {**valid}
incomplete.pop('cache_ttl_s', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
assert results[0] == 'PASS' and results[2].startswith('MISSING'), results

